// Parse dispute event
const payload = $input.first().json.body || $input.first().json;
const d = payload.data || {};

return [{
  json: {
    event: 'dispute.opened',
    disputeId: d.disputeId,
    contractId: d.contractId,
    milestoneSeq: d.milestoneSeq,
    filedBy: d.filedBy,
    reason: d.reason,
    creatorId: d.creatorId,
    marketplaceId: d.marketplaceId,
    amount: d.amount,
    currency: d.currency,
    timestamp: payload.timestamp,
    // 7-day direct resolution window
    directResolutionDeadline: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
  }
}];

// Notify both parties about the dispute
const data = $input.first().json;

console.log(`[StudioLedger] DISPUTE OPENED: ${data.disputeId}`);
console.log(`[StudioLedger] Contract: ${data.contractId}, Milestone: ${data.milestoneSeq}`);
console.log(`[StudioLedger] Filed by: ${data.filedBy}`);
console.log(`[StudioLedger] Reason: ${data.reason}`);
console.log(`[StudioLedger] Amount at stake: ${data.amount} ${data.currency}`);
console.log(`[StudioLedger] Direct resolution deadline: ${data.directResolutionDeadline}`);

return [{
  json: {
    ...data,
    notification: 'dispute_opened',
    tier: 1,
    tierName: 'Direct Resolution',
    message: `Dispute opened — 7-day direct resolution window started`
  }
}];

// Start 7-day timer for Tier 1 (Direct Resolution)
const data = $input.first().json;

console.log(`[StudioLedger] TIER 1 TIMER: Direct resolution window for dispute ${data.disputeId}`);
console.log(`[StudioLedger] Deadline: ${data.directResolutionDeadline}`);
console.log(`[StudioLedger] If unresolved, will escalate to Tier 2 (Platform Mediated Review)`);

// In production: use n8n Wait node or scheduled trigger
// to check dispute status after 7 days and auto-escalate

return [{
  json: {
    ...data,
    escalationScheduled: true,
    nextTier: 2,
    nextTierName: 'Platform-Mediated Review',
    message: `Escalation to Tier 2 scheduled if unresolved by ${data.directResolutionDeadline}`
  }
}];

// Log dispute pipeline status
const data = $input.first().json;

const summary = {
  disputeId: data.disputeId,
  contractId: data.contractId,
  status: 'tier_1_active',
  tier: 1,
  tierName: 'Direct Resolution',
  filedBy: data.filedBy,
  amount: `${data.amount} ${data.currency}`,
  directResolutionDeadline: data.directResolutionDeadline,
  escalationScheduled: data.escalationScheduled,
  processedAt: new Date().toISOString()
};

console.log('[StudioLedger] Dispute pipeline complete:', JSON.stringify(summary));

return [{ json: summary }];
